class Solution:
    def crackSafe(self, n: int, k: int) -> str:
        res = '0' * n
        visit = set([res])
        for _ in range(k ** n):
            prefix = res[-n + 1:]
            for x in range(k - 1, -1, -1):
                curr = prefix + str(x)
                if curr not in visit:
                    visit.add(curr)
                    res += str(x)
                    break
        return res

